export function translate(dict, lang, key, vars) {
  const tr = dict[lang];
  const fr = dict['fr'];
  let s = (tr?.[key] ?? fr?.[key]) ?? key;
  if (vars) Object.keys(vars).forEach(k => s = s.replace(new RegExp(`\\{${k}}`, 'g'), vars[k]));
  return s;
}
